import React, { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { studentAPI, attendanceAPI, examinationAPI, courseAPI, feeAPI } from '../services/api';
import { useNavigate } from 'react-router-dom';

const FacultyDashboard = () => {
  const { hasRole, user } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats] = useState({
    totalStudents: 0,
    presentToday: 0,
    upcomingExams: 0,
    pendingFees: 0,
    averageAttendance: 0,
    coursesCount: 0,
    recentActivities: []
  });
  const [loading, setLoading] = useState(true);
  const [selectedPeriod, setSelectedPeriod] = useState('today');
  const [viewMode, setViewMode] = useState('grid'); // 'grid' or 'list'

  useEffect(() => {
    if (hasRole('FACULTY')) {
      fetchDashboardData();
    }
  }, [selectedPeriod]);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);

      // Fetch data for faculty-specific metrics
      const [studentsRes, attendanceRes, examsRes, coursesRes, feesRes] = await Promise.all([
        studentAPI.getAll(),
        attendanceAPI.getAll(),
        examinationAPI.getAll(),
        courseAPI.getAll(),
        feeAPI.getAll()
      ]);

      const students = studentsRes.data || [];
      const attendance = attendanceRes.data || [];
      const exams = examsRes.data || [];
      const courses = coursesRes.data || [];
      const fees = feesRes.data || [];

      // Calculate faculty-specific statistics
      const today = new Date();
      const todayAttendance = attendance.filter(a => 
        new Date(a.date).toDateString() === today.toDateString()
      );

      const upcomingExams = exams.filter(exam => 
        new Date(exam.examDate) > today
      );

      const pendingFees = fees.filter(fee => 
        fee.status === 'Pending' || fee.status === 'Partial'
      );

      const averageAttendance = students.length > 0 ? 
        (todayAttendance.length / students.length) * 100 : 0;

      // Recent activities for faculty
      const recentActivities = [
        ...attendance.slice(0, 3).map(a => ({
          type: 'attendance',
          title: `Attendance marked for ${a.student?.firstName || 'Student'}`,
          time: new Date(a.date).toLocaleTimeString(),
          icon: '📝',
          color: 'blue'
        })),
        ...exams.slice(0, 2).map(e => ({
          type: 'exam',
          title: `Exam: ${e.title}`,
          time: new Date(e.examDate).toLocaleDateString(),
          icon: '📋',
          color: 'purple'
        }))
      ].sort((a, b) => new Date(b.time) - new Date(a.time));

      setStats({
        totalStudents: students.length,
        presentToday: todayAttendance.length,
        upcomingExams: upcomingExams.length,
        pendingFees: pendingFees.length,
        averageAttendance: Math.round(averageAttendance),
        coursesCount: courses.length,
        recentActivities
      });
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  // Check if user has faculty role
  if (!hasRole('FACULTY')) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <h1 className="text-3xl font-bold text-gray-900 mb-4">🚫 Access Denied</h1>
          <p className="text-gray-600 text-lg">This dashboard is only available to faculty members.</p>
          <p className="text-gray-500 mt-2">Please contact your administrator if you need access.</p>
        </div>
      </div>
    );
  }

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      minimumFractionDigits: 0
    }).format(amount || 0);
  };

  // Button click handlers
  const handleMarkAttendance = () => {
    navigate('/attendance');
  };

  const handleCreateExam = () => {
    navigate('/examinations');
  };

  const handleViewStudents = () => {
    navigate('/students');
  };

  const handleFeeStatus = () => {
    navigate('/fees');
  };

  const getStatCard = (title, value, icon, color, subtitle = '') => {
    const colorClasses = {
      blue: 'from-blue-500 to-blue-600',
      green: 'from-green-500 to-green-600',
      purple: 'from-purple-500 to-purple-600',
      orange: 'from-orange-500 to-orange-600',
      red: 'from-red-500 to-red-600',
      indigo: 'from-indigo-500 to-indigo-600'
    };

    return (
      <div className="bg-white rounded-xl shadow-lg overflow-hidden hover:shadow-xl transition-shadow duration-300">
        <div className={`bg-gradient-to-r ${colorClasses[color]} p-4`}>
          <div className="flex items-center justify-between">
            <div>
              <p className="text-white text-sm font-medium opacity-90">{title}</p>
              <p className="text-white text-2xl font-bold">{value}</p>
              {subtitle && <p className="text-white text-xs opacity-75 mt-1">{subtitle}</p>}
            </div>
            <span className="text-3xl opacity-80">{icon}</span>
          </div>
        </div>
      </div>
    );
  };

  const getActivityItem = (activity) => {
    const colorClasses = {
      blue: 'bg-blue-50 border-blue-200 text-blue-700',
      purple: 'bg-purple-50 border-purple-200 text-purple-700',
      green: 'bg-green-50 border-green-200 text-green-700',
      orange: 'bg-orange-50 border-orange-200 text-orange-700'
    };

    return (
      <div className={`p-4 rounded-lg border ${colorClasses[activity.color]} hover:shadow-md transition-shadow`}>
        <div className="flex items-start space-x-3">
          <span className="text-2xl">{activity.icon}</span>
          <div className="flex-1">
            <h4 className="font-semibold text-sm">{activity.title}</h4>
            <p className="text-xs opacity-75 mt-1">{activity.time}</p>
          </div>
        </div>
      </div>
    );
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
          <p className="text-gray-600 text-lg">Loading faculty dashboard...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <div className="bg-white shadow-sm border-b">
        <div className="container mx-auto px-4 py-4">
          <div className="flex justify-between items-center">
            <div>
              <h1 className="text-2xl font-bold text-gray-900 flex items-center">
                <span className="mr-3">👨‍🏫</span>
                Faculty Dashboard
              </h1>
              <p className="text-gray-600 text-sm mt-1">
                Welcome back, {user?.firstName || 'Faculty Member'}!
              </p>
            </div>
            <div className="flex items-center space-x-4">
              <select
                value={selectedPeriod}
                onChange={(e) => setSelectedPeriod(e.target.value)}
                className="px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              >
                <option value="today">Today</option>
                <option value="week">This Week</option>
                <option value="month">This Month</option>
              </select>
              <button
                onClick={() => setViewMode(viewMode === 'grid' ? 'list' : 'grid')}
                className="bg-gray-100 text-gray-700 px-4 py-2 rounded-lg hover:bg-gray-200 transition-colors flex items-center"
              >
                <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16m-7-6h7m-7 6h7" />
                </svg>
                {viewMode === 'grid' ? 'List View' : 'Grid View'}
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="container mx-auto px-4 py-8">
        {/* Quick Actions */}
        <div className="mb-8">
          <h2 className="text-xl font-semibold text-gray-900 mb-4 flex items-center">
            <span className="mr-2">⚡</span>
            Quick Actions
          </h2>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            <button 
              onClick={handleMarkAttendance}
              className="bg-gradient-to-r from-blue-500 to-blue-600 text-white p-4 rounded-lg hover:from-blue-600 hover:to-blue-700 transition-all duration-200 flex items-center justify-center"
            >
              <span className="mr-2">📝</span>
              <span className="font-medium">Mark Attendance</span>
            </button>
            <button 
              onClick={handleCreateExam}
              className="bg-gradient-to-r from-green-500 to-green-600 text-white p-4 rounded-lg hover:from-green-600 hover:to-green-700 transition-all duration-200 flex items-center justify-center"
            >
              <span className="mr-2">📋</span>
              <span className="font-medium">Create Exam</span>
            </button>
            <button 
              onClick={handleViewStudents}
              className="bg-gradient-to-r from-purple-500 to-purple-600 text-white p-4 rounded-lg hover:from-purple-600 hover:to-purple-700 transition-all duration-200 flex items-center justify-center"
            >
              <span className="mr-2">👥</span>
              <span className="font-medium">View Students</span>
            </button>
            <button 
              onClick={handleFeeStatus}
              className="bg-gradient-to-r from-orange-500 to-orange-600 text-white p-4 rounded-lg hover:from-orange-600 hover:to-orange-700 transition-all duration-200 flex items-center justify-center"
            >
              <span className="mr-2">💰</span>
              <span className="font-medium">Fee Status</span>
            </button>
          </div>
        </div>

        {/* Statistics Cards */}
        <div className="mb-8">
          <h2 className="text-xl font-semibold text-gray-900 mb-4 flex items-center">
            <span className="mr-2">📊</span>
            Your Teaching Statistics
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {getStatCard('Total Students', stats.totalStudents, '👥', 'blue', 'Under your guidance')}
            {getStatCard('Present Today', stats.presentToday, '✅', 'green', `${stats.averageAttendance}% attendance`)}
            {getStatCard('Upcoming Exams', stats.upcomingExams, '📅', 'purple', 'Next 7 days')}
            {getStatCard('Pending Fees', stats.pendingFees, '💳', 'orange', 'Payment pending')}
            {getStatCard('Avg Attendance', `${stats.averageAttendance}%`, '📈', 'indigo', 'This month')}
            {getStatCard('Active Courses', stats.coursesCount, '📚', 'red', 'This semester')}
          </div>
        </div>

        {/* Recent Activities */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          {/* Activities Feed */}
          <div>
            <h2 className="text-xl font-semibold text-gray-900 mb-4 flex items-center">
              <span className="mr-2">🔔</span>
              Recent Activities
            </h2>
            <div className="space-y-3">
              {stats.recentActivities.length === 0 ? (
                <div className="bg-white rounded-lg p-6 text-center text-gray-500">
                  <span className="text-2xl mb-2 block">📭</span>
                  No recent activities
                </div>
              ) : (
                stats.recentActivities.map((activity, index) => (
                  <div key={index}>
                    {getActivityItem(activity)}
                  </div>
                ))
              )}
            </div>
          </div>

          {/* Performance Overview */}
          <div>
            <h2 className="text-xl font-semibold text-gray-900 mb-4 flex items-center">
              <span className="mr-2">📈</span>
              Performance Overview
            </h2>
            <div className="bg-white rounded-xl shadow-lg p-6">
              {/* Attendance Chart Placeholder */}
              <div className="mb-6">
                <h3 className="text-lg font-semibold text-gray-900 mb-3">Attendance Trend</h3>
                <div className="bg-gray-50 rounded-lg p-4 h-32 flex items-center justify-center">
                  <div className="text-center">
                    <span className="text-4xl mb-2 block">📊</span>
                    <p className="text-gray-600">Attendance analytics coming soon</p>
                  </div>
                </div>
              </div>

              {/* Student Performance */}
              <div>
                <h3 className="text-lg font-semibold text-gray-900 mb-3">Class Performance</h3>
                <div className="grid grid-cols-2 gap-4">
                  <div className="bg-green-50 rounded-lg p-4 text-center">
                    <span className="text-2xl mb-2 block">🌟</span>
                    <p className="text-green-700 font-semibold">Excellent</p>
                    <p className="text-sm text-green-600">85%+ students</p>
                  </div>
                  <div className="bg-yellow-50 rounded-lg p-4 text-center">
                    <span className="text-2xl mb-2 block">📚</span>
                    <p className="text-yellow-700 font-semibold">Good</p>
                    <p className="text-sm text-yellow-600">70-85% students</p>
                  </div>
                </div>
              </div>

              {/* Quick Stats */}
              <div className="mt-6 pt-6 border-t border-gray-200">
                <div className="grid grid-cols-2 gap-4 text-sm">
                  <div>
                    <span className="text-gray-600">Best Performing Class:</span>
                    <p className="font-semibold text-gray-900">Computer Science - Semester 3</p>
                  </div>
                  <div>
                    <span className="text-gray-600">Average Score:</span>
                    <p className="font-semibold text-gray-900">78.5%</p>
                  </div>
                  <div>
                    <span className="text-gray-600">Improvement Rate:</span>
                    <p className="font-semibold text-green-600">+12.3%</p>
                  </div>
                  <div>
                    <span className="text-gray-600">Student Satisfaction:</span>
                    <p className="font-semibold text-blue-600">4.5/5.0</p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Schedule Overview */}
        <div className="mt-8">
          <h2 className="text-xl font-semibold text-gray-900 mb-4 flex items-center">
            <span className="mr-2">📅</span>
            Today's Schedule
          </h2>
          <div className="bg-white rounded-xl shadow-lg p-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="border-l-4 border-blue-500 pl-4">
                <div className="text-sm text-gray-600">9:00 AM - 10:30 AM</div>
                <div className="font-semibold text-gray-900">Computer Science - Semester 3</div>
                <div className="text-sm text-gray-600">Room: CS-301</div>
              </div>
              <div className="border-l-4 border-green-500 pl-4">
                <div className="text-sm text-gray-600">11:00 AM - 12:30 PM</div>
                <div className="font-semibold text-gray-900">Data Structures Lab</div>
                <div className="text-sm text-gray-600">Lab: CS-LAB-2</div>
              </div>
              <div className="border-l-4 border-purple-500 pl-4">
                <div className="text-sm text-gray-600">2:00 PM - 3:30 PM</div>
                <div className="font-semibold text-gray-900">Faculty Meeting</div>
                <div className="text-sm text-gray-600">Conference Room</div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default FacultyDashboard;
